const CLIENT_ID = 'mobile_app_client_123';
const REDIRECT_URI = 'myapp://oauth/callback';
const AUTHORIZATION_ENDPOINT = 'https://auth.example.com/oauth/authorize';
const TOKEN_ENDPOINT = 'https://auth.example.com/oauth/token';

export async function exchangeAuthorizationCode(code) {
  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code,
    redirect_uri: REDIRECT_URI,
    client_id: CLIENT_ID,
  });

  const response = await fetch(TOKEN_ENDPOINT, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Token exchange failed: ${response.status} ${errorText}`);
  }

  return response.json();
}

export function buildAuthorizationUrl(state, codeChallenge) {
  const params = new URLSearchParams({
    response_type: 'code',
    client_id: CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    scope: 'openid profile email',
    state,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
  });

  return `${AUTHORIZATION_ENDPOINT}?${params.toString()}`;
}

import React, { useEffect, useMemo, useState } from 'react';
import { SafeAreaView, View, Text, Pressable, ActivityIndicator, Alert } from 'react-native';
import * as WebBrowser from 'expo-web-browser';
import * as Linking from 'expo-linking';
import * as Crypto from 'expo-crypto';

WebBrowser.maybeCompleteAuthSession();

function base64UrlEncode(input) {
  return input
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

async function sha256(input) {
  const digest = await Crypto.digestStringAsync(Crypto.CryptoDigestAlgorithm.SHA256, input, {
    encoding: Crypto.CryptoEncoding.BASE64,
  });
  return base64UrlEncode(digest);
}

async function createPkcePair() {
  const verifierBytes = Crypto.getRandomBytes(32);
  const verifier = base64UrlEncode(Buffer.from(verifierBytes).toString('base64'));
  const challenge = await sha256(verifier);
  return { verifier, challenge };
}

export default function App() {
  const [loading, setLoading] = useState(false);
  const [tokens, setTokens] = useState(null);

  const redirectUrl = useMemo(() => Linking.createURL('oauth/callback'), []);

  useEffect(() => {
    const subscription = Linking.addEventListener('url', async ({ url }) => {
      try {
        const parsed = Linking.parse(url);
        const code = parsed?.queryParams?.code;
        if (!code) return;
        setLoading(true);
        const tokenResponse = await exchangeAuthorizationCode(code);
        setTokens(tokenResponse);
      } catch (e) {
        Alert.alert('Authentication Error', e.message);
      } finally {
        setLoading(false);
      }
    });

    return () => subscription.remove();
  }, []);

  const signIn = async () => {
    try {
      setLoading(true);
      const state = String(Date.now());
      const { verifier, challenge } = await createPkcePair();
      globalThis.__pkceVerifier = verifier;
      const authUrl = buildAuthorizationUrl(state, challenge);
      const result = await WebBrowser.openAuthSessionAsync(authUrl, redirectUrl);

      if (result.type === 'success' && result.url) {
        const parsed = Linking.parse(result.url);
        const code = parsed?.queryParams?.code;
        if (!code) throw new Error('No authorization code returned');
        const tokenResponse = await exchangeAuthorizationCode(code);
        setTokens(tokenResponse);
      }
    } catch (e) {
      Alert.alert('Sign In Failed', e.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={{ flex: 1, alignItems: 'center', justifyContent: 'center', padding: 24 }}>
      <View style={{ width: '100%', maxWidth: 360 }}>
        <Text style={{ fontSize: 28, fontWeight: '700', marginBottom: 16 }}>OAuth Demo</Text>
        {tokens ? (
          <Text selectable style={{ marginBottom: 16 }}>
            {JSON.stringify(tokens, null, 2)}
          </Text>
        ) : (
          <Text style={{ marginBottom: 16 }}>Sign in to continue.</Text>
        )}
        <Pressable
          onPress={signIn}
          disabled={loading}
          style={{
            backgroundColor: loading ? '#999' : '#2563eb',
            paddingVertical: 14,
            borderRadius: 10,
            alignItems: 'center',
          }}
        >
          {loading ? <ActivityIndicator color="#fff" /> : <Text style={{ color: '#fff', fontWeight: '600' }}>Sign In</Text>}
        </Pressable>
      </View>
    </SafeAreaView>
  );
}